import React from 'react';

function user(props){
    const {isLoggedIn} = props;
    return (
        <div className="user-card position-absolute top-50 start-0 p-2" hidden={isLoggedIn === true}>
            <div className="user-card-sidebar">
                <ul className="user-settings">
                    <li className="user-settings-item">setting</li>
                    <li className="user-settings-item">
                        <button>Appearance</button>
                    </li>
                    <li className="user-settings-item">
                        <button>Help</button>
                    </li>
                </ul>
            </div>
            <div className="user-card-container">
                <div className="user-picture-container">
                    <i className="bi bi-person"> </i>
                </div>
                <h1>USER</h1>
            </div>
        </div>
    );
}

export default user;
